"use client";

import * as React from "react";

import { Button, type ButtonProps } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Switch } from "@/components/ui/switch";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { cn } from "@/lib/utils";

export function RealmorphismShell({ className, ...props }: React.HTMLAttributes<HTMLDivElement>) {
  return <div className={cn("theme-realmorphism bg-background text-foreground", className)} {...props} />;
}

export function RealmorphismButton({ className, ...props }: ButtonProps) {
  return <Button className={cn("realmorphism-action rounded-[var(--radius)]", className)} {...props} />;
}

export function RealmorphismIconButton({ className, ...props }: ButtonProps) {
  return <RealmorphismButton size="icon" className={cn("size-10", className)} {...props} />;
}

export function RealmorphismCard({ className, ...props }: React.ComponentProps<typeof Card>) {
  return (
    <Card
      className={cn(
        "rounded-[var(--radius)] border border-[var(--realmorphism-face-border)] bg-[var(--realmorphism-host-raised)] shadow-[var(--realmorphism-shadow-rest)]",
        className
      )}
      {...props}
    />
  );
}

export function RealmorphismInput({ className, ...props }: React.ComponentProps<typeof Input>) {
  return (
    <Input
      className={cn(
        "rounded-[var(--radius)] border-[var(--realmorphism-face-border)] bg-[var(--realmorphism-face)] text-[var(--realmorphism-ink-on-face)] shadow-[var(--realmorphism-shadow-rest)] focus-visible:-translate-x-0.5 focus-visible:-translate-y-0.5 focus-visible:shadow-[var(--realmorphism-shadow-hover)]",
        className
      )}
      {...props}
    />
  );
}

export function RealmorphismSwitch({ className, ...props }: React.ComponentProps<typeof Switch>) {
  return <Switch className={cn("realmorphism-action", className)} {...props} />;
}

export function RealmorphismToolbar({ className, ...props }: React.HTMLAttributes<HTMLDivElement>) {
  return (
    <div
      className={cn(
        "flex items-center gap-2 rounded-[var(--radius)] border border-[var(--realmorphism-face-border)] bg-[var(--realmorphism-host)] p-2",
        className
      )}
      {...props}
    />
  );
}

export function RealmorphismTabs({ className, ...props }: React.ComponentProps<typeof Tabs>) {
  return <Tabs className={cn("theme-realmorphism", className)} {...props} />;
}

export function RealmorphismTabsList({ className, ...props }: React.ComponentProps<typeof TabsList>) {
  return (
    <TabsList
      className={cn(
        "gap-2 rounded-[var(--radius)] border border-[var(--realmorphism-face-border)] bg-[var(--realmorphism-host)] p-1",
        className
      )}
      {...props}
    />
  );
}

export function RealmorphismTabsTrigger({ className, ...props }: React.ComponentProps<typeof TabsTrigger>) {
  return <TabsTrigger className={cn("realmorphism-action", className)} {...props} />;
}

export { CardContent, CardDescription, CardFooter, CardHeader, CardTitle, TabsContent };
